using System.ComponentModel;
using System.Net;
using System.Text;
using System.Text.RegularExpressions;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

const string modelId = "gpt-4o-mini-2024-07-18";

// --- Shared state for the note-taking tool ---
var notes = new List<string>();

// --- Tool definitions ---
var httpClient = new HttpClient();
httpClient.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");

[Description("Search the web for information on a query. Returns up to 5 result snippets.")]
async Task<string> WebSearch(
    [Description("The search query to look up")] string query)
{
    Console.WriteLine($"  \u001b[36m🔍 Searching:\u001b[0m {query}");

    var encoded = Uri.EscapeDataString(query);
    var url = $"https://html.duckduckgo.com/html/?q={encoded}";

    try
    {
        var html = await httpClient.GetStringAsync(url);

        var snippets = Regex.Matches(html,
            @"<a class=""result__snippet""[^>]*>(.*?)</a>", RegexOptions.Singleline);
        var titles = Regex.Matches(html,
            @"<a class=""result__a""[^>]*>(.*?)</a>", RegexOptions.Singleline);

        var sb = new StringBuilder();
        var count = Math.Min(snippets.Count, 5);
        for (var i = 0; i < count; i++)
        {
            var title = i < titles.Count
                ? StripHtml(titles[i].Groups[1].Value)
                : $"Result {i + 1}";
            var snippet = StripHtml(snippets[i].Groups[1].Value);
            sb.AppendLine($"- {title}: {snippet}");
        }

        return sb.Length > 0 ? sb.ToString() : "No results found for this query.";
    }
    catch (HttpRequestException ex)
    {
        return $"Search failed: {ex.Message}";
